  1	import * as React from 'react';
  2	import { mount, ReactWrapper } from 'enzyme';
  3	import { ComponentStatus, Status } from '../../../types/IstioStatus';
  4	import { IstioStatusComponent } from '../IstioStatus';
  5	import { mountToJson } from 'enzyme-to-json';
  6	import { CLUSTER_DEFAULT } from '../../../types/Graph';
  7	import { serverConfig } from '../../../config';
  8	import { setServerConfig } from '../../../config/ServerConfig';
  9	import { MemoryRouter } from 'react-router-dom-v5-compat';
 10	
 11	const mockIcon = (componentList: ComponentStatus[]): ReactWrapper => {
 12	  return mount(
 13	    <MemoryRouter>
 14	      <IstioStatusComponent
 15	        statusMap={{ Kubernetes: componentList }}
 16	        lastRefreshAt={848152}
 17	        namespaces={[
 18	          { name: 'bookinfo', cluster: CLUSTER_DEFAULT },
 19	          { name: 'istio-system', cluster: CLUSTER_DEFAULT }
 20	        ]}
 21	        setIstioStatus={jest.fn()}
 22	      />
 23	    </MemoryRouter>
 24	  );
 25	};
 26	
 27	const testSnapshot = (wrapper: any): void => {
 28	  const component = wrapper.find('IstioStatusComponent').first();
 29	  expect(mountToJson(component)).toBeDefined();
 30	  expect(mountToJson(component)).toMatchSnapshot();
 31	};
 32	
 33	const testTooltip = (wrapper: any): void => {
 34	  const tooltip = wrapper.find('Tooltip').first();
 35	  expect(tooltip.exists()).toBe(true);
 36	  expect(tooltip.props().position).toEqual('top');
 37	  expect(tooltip.props().enableFlip).toEqual(true);
 38	};
 39	
 40	const testIcon = (wrapper: any, dataTest: string, iconName: string): void => {
 41	  const iconWrapper = wrapper.find(`[data-test="${dataTest}"]`).first();
 42	  expect(iconWrapper.exists()).toBe(true);
 43	  const iconComponent = iconWrapper.find(iconName).first();
 44	  expect(iconComponent.exists()).toBe(true);
 45	};
 46	
 47	jest.mock('../../../utils/MeshUtils', () => ({
 48	  isControlPlaneAccessible: () => true
 49	}));
 50	
 51	describe('When core component has a problem', () => {
 52	  beforeEach(() => {
 53	    serverConfig.clusters = {
 54	      CLUSTER_DEFAULT: {
 55	        accessible: true,
 56	        apiEndpoint: '',
 57	        isKialiHome: true,
 58	        kialiInstances: [],
 59	        name: CLUSTER_DEFAULT,
 60	        secretName: 'test-secret'
 61	      }
 62	    };
 63	    setServerConfig(serverConfig);
 64	  });
