  1	import * as React from 'react';
  2	import { SVGIconProps } from '@patternfly/react-icons/dist/js/createIcon';
  3	import * as API from '../../services/Api';
  4	import * as AlertUtils from '../../utils/AlertUtils';
  5	import { TimeInMilliseconds } from '../../types/Common';
  6	import { ComponentStatus, Status, statusSeverity } from '../../types/IstioStatus';
  7	import { MessageType } from '../../types/MessageCenter';
  8	import { Namespace } from '../../types/Namespace';
  9	import { KialiAppState } from '../../store/Store';
 10	import { istioStatusSelector, namespaceItemsSelector } from '../../store/Selectors';
 11	import { IstioStatusActions } from '../../actions/IstioStatusActions';
 12	import { connect } from 'react-redux';
 13	import { Content, ContentVariants, Tooltip, TooltipPosition, Label } from '@patternfly/react-core';
 14	import { IstioStatusList } from './IstioStatusList';
 15	import { PFColors } from '../Pf/PfColors';
 16	import {
 17	  CheckCircleIcon,
 18	  ExclamationCircleIcon,
 19	  ExclamationTriangleIcon,
 20	  InfoCircleIcon,
 21	  QuestionCircleIcon
 22	} from '@patternfly/react-icons';
 23	import { KialiDispatch } from 'types/Redux';
 24	import { connectRefresh } from '../Refresh/connectRefresh';
 25	import { kialiStyle } from 'styles/StyleUtils';
 26	import { IconProps, createIcon, KialiIcon } from 'config/KialiIcon';
 27	import { Link, useLocation } from 'react-router-dom-v5-compat';
 28	import { useKialiTranslation } from 'utils/I18nUtils';
 29	import { isControlPlaneAccessible } from '../../utils/MeshUtils';
 30	import { homeCluster } from '../../config';
 31	import { PFBadge, PFBadges } from '../Pf/PfBadges';
 32	
 33	export type ClusterStatusMap = { [cluster: string]: ComponentStatus[] };
 34	
 35	type ReduxStateProps = {
 36	  namespaces?: Namespace[];
 37	  statusMap: ClusterStatusMap; // map of clusters to ComponentStatus[]
 38	};
 39	
 40	type ReduxDispatchProps = {
 41	  setIstioStatus: (statusMap: ClusterStatusMap) => void;
 42	};
 43	
 44	type StatusIcons = {
 45	  ErrorIcon?: React.ComponentClass<SVGIconProps>;
 46	  HealthyIcon?: React.ComponentClass<SVGIconProps>;
 47	  InfoIcon?: React.ComponentClass<SVGIconProps>;
 48	  WarningIcon?: React.ComponentClass<SVGIconProps>;
 49	};
 50	
 51	type Props = ReduxStateProps &
 52	  ReduxDispatchProps & {
 53	    icons?: StatusIcons;
 54	    lastRefreshAt: TimeInMilliseconds;
 55	  };
 56	
 57	const ValidToColor = {
 58	  'true-true-true': PFColors.Danger,
 59	  'true-true-false': PFColors.Danger,
 60	  'true-false-true': PFColors.Danger,
 61	  'true-false-false': PFColors.Danger,
 62	  'false-true-true': PFColors.Warning,
 63	  'false-true-false': PFColors.Warning,
 64	  'false-false-true': PFColors.Info,
 65	  'false-false-false': PFColors.Success
 66	};
 67	
 68	const defaultIcons = {
 69	  ErrorIcon: ExclamationCircleIcon,
 70	  HealthyIcon: CheckCircleIcon,
 71	  InfoIcon: InfoCircleIcon,
 72	  WarningIcon: ExclamationTriangleIcon
 73	};
 74	
 75	const iconStyle = kialiStyle({
 76	  marginLeft: '0.5rem',
 77	  fontSize: '1rem'
 78	});
 79	
 80	const clusterStyle = kialiStyle({
 81	  display: 'flex',
 82	  alignItems: 'center'
 83	});
 84	
 85	const labelStyle = kialiStyle({
 86	  $nest: {
 87	    '& .pf-v6-c-label__icon': {
 88	      marginRight: '0.5rem'
 89	    }
 90	  }
 91	});
 92	
 93	export const meshLinkStyle = kialiStyle({
 94	  display: 'flex',
 95	  justifyContent: 'center',
 96	  marginTop: '0.75rem',
 97	  $nest: {
 98	    '& > span': {
 99	      marginRight: '0.5rem'
100	    }
101	  }
102	});
103	
104	export const IstioStatusComponent: React.FC<Props> = (props: Props) => {
105	  const { t } = useKialiTranslation();
106	  const { pathname } = useLocation();
107	
108	  const { namespaces, setIstioStatus, lastRefreshAt } = props;
109	
110	  const fetchStatus = React.useCallback((): void => {
111	    API.getIstioStatus()
112	      .then(response => {
113	        const statusMap: ClusterStatusMap = {};
114	
115	        response.data.forEach(status => {
116	          if (!statusMap[status.cluster]) {
117	            statusMap[status.cluster] = [];
118	          }
119	          statusMap[status.cluster].push(status);
120	        });
121	
122	        setIstioStatus(statusMap);
123	      })
124	      .catch(error => {
125	        // User without namespaces can't have access to mTLS information. Reduce severity to info.
126	        const informative = namespaces && namespaces.length < 1;
127	
128	        if (informative) {
129	          AlertUtils.addError(t('Istio deployment status disabled.'), error, 'default', MessageType.INFO);
130	        } else {
131	          AlertUtils.addError(t('Error fetching Istio deployment status.'), error, 'default', MessageType.ERROR);
132	        }
133	      });
134	  }, [namespaces, setIstioStatus, t]);
135	
136	  React.useEffect(() => {
137	    // retrieve status for all clusters
138	    fetchStatus();
139	  }, [pathname, lastRefreshAt, fetchStatus]);
140	
141	  const getSeverity = (components: ComponentStatus[]): number =>
142	    Math.max(
143	      ...components.map(
144	        cs =>
145	          statusSeverity[cs.status] +
146	          (cs.isCore && statusSeverity[cs.status] !== statusSeverity[Status.Healthy] ? 10 : 0)
147	      )
148	    ); // non health core component has much higher severity
149	
150	  const sortedClusters = Object.keys(props.statusMap).sort((a, b) => {
151	    const worstA = getSeverity(props.statusMap[a]);
152	    const worstB = getSeverity(props.statusMap[b]);
153	    return worstB - worstA;
154	  });
155	
156	  const tooltipContent = (): React.ReactNode => {
157	    return (
158	      <>
159	        <Content style={{ color: PFColors.White }}>
160	          <Content component={ContentVariants.h4}>{t('Cluster Status')}</Content>
